// Parser l'?v?nement Stripe
const body = $input.first().json.body || $input.first().json;

const eventType = body.type || '';
const dataObj = (body.data && body.data.object) || {};

// Extraire les champs selon le type d'?v?nement
let customerEmail = '';
let customerId = '';
let planFromMetadata = '';
let subscriptionId = '';
let subscriptionStatus = '';
let newPlan = '';

if (eventType === 'checkout.session.completed') {
  customerEmail = dataObj.customer_email || dataObj.customer_details?.email || '';
  customerId = dataObj.customer || '';
  subscriptionId = dataObj.subscription || '';
  // R?cup?rer le plan depuis les m?tadonn?es de la session
  planFromMetadata = (dataObj.metadata && dataObj.metadata.plan) || 'starter';
}

if (eventType === 'customer.subscription.updated') {
  customerId = dataObj.customer || '';
  subscriptionId = dataObj.id || '';
  subscriptionStatus = dataObj.status || '';
  // Le plan vient du premier item de la subscription
  const item = dataObj.items?.data?.[0];
  newPlan = (item?.price?.metadata?.plan) || (item?.plan?.metadata?.plan) || 'starter';
}

if (eventType === 'customer.subscription.deleted') {
  customerId = dataObj.customer || '';
  subscriptionId = dataObj.id || '';
}

return [{
  json: {
    eventType,
    customerEmail,
    customerId,
    subscriptionId,
    planFromMetadata,
    subscriptionStatus,
    newPlan,
    rawData: dataObj
  }
}];

// Pr?parer email de bienvenue
const eventData = $('Code - Parser ?v?nement Stripe').item.json;
const email = eventData.customerEmail;
const plan = eventData.planFromMetadata || 'starter';
const prenom = email.split('@')[0];

const planLabels = { starter: 'Starter', pro: 'Pro', booster: 'Booster' };
const planLabel = planLabels[plan] || 'Starter';

const tallyUrl = `https://tally.so/r/b5kE41?email=${encodeURIComponent(email)}`;

const html = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <h1 style="color: #2563eb;">Bienvenue sur ApplyFlow ! ??</h1>
  <p>Bonjour ${prenom},</p>
  <p>Votre abonnement <strong>${planLabel}</strong> (${plan === 'starter' ? '9' : plan === 'pro' ? '19' : '39'} CHF/mois) est maintenant actif.</p>

  <div style="background:#f0f9ff; padding:16px; border-radius:8px; margin:16px 0;">
    <h3 style="margin:0 0 8px; color:#2563eb;">?? Premi?re ?tape : compl?ter votre profil</h3>
    <p style="margin:0 0 12px;">Pour recevoir des alertes emploi personnalis?es, configurez votre profil :</p>
    <a href="${tallyUrl}" style="display:inline-block; padding:12px 24px; background:#2563eb; color:white; border-radius:8px; text-decoration:none; font-size:16px;">
      Compl?ter mon profil ?
    </a>
  </div>

  <h3>Ce que vous pouvez faire avec ApplyFlow :</h3>
  <ul>
    <li>? Recevoir des alertes emploi personnalis?es 2x/jour</li>
    ${plan !== 'starter' ? '<li>? G?n?rer des lettres de motivation en 30 secondes</li>' : '<li>? G?n?ration LM (disponible d?s le plan Pro)</li>'}
    ${plan !== 'starter' ? '<li>? Suivre vos candidatures dans le CRM</li>' : ''}
  </ul>

  <p>Vous d?finirez votre mot de passe via l'email de v?rification envoy? par ApplyFlow.</p>

  <p style="color:#6b7280; font-size:12px; margin-top:24px;">
    Des questions ? R?pondez ? cet email, nous sommes l? pour vous aider.<br>
    ApplyFlow - La recherche d'emploi automatis?e en Suisse romande
  </p>
</div>
`;

return [{
  json: { email, prenom, plan, html, subject: `Bienvenue sur ApplyFlow ${prenom} ! Votre abonnement ${planLabel} est actif ??` }
}];

// Pr?parer email de fin d'abonnement
const eventData = $('Code - Parser ?v?nement Stripe').item.json;
const customerId = eventData.customerId;

// R?cup?rer l'email depuis le profil d?sactiv?
const profil = $('Supabase - D?sactiver utilisateur').item.json;
const email = profil.email || '';
const prenom = email ? email.split('@')[0] : '';

const html = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <h2 style="color: #6b7280;">Votre abonnement ApplyFlow a ?t? r?sili?</h2>
  <p>Bonjour ${prenom},</p>
  <p>Nous avons bien pris en compte la r?siliation de votre abonnement. Votre acc?s ? ApplyFlow est maintenant suspendu.</p>

  <div style="background:#fef2f2; padding:16px; border-radius:8px; margin:16px 0; border-left:4px solid #ef4444;">
    <p style="margin:0;">Vos donn?es sont conserv?es pendant 30 jours. Si vous vous r?abonnez dans ce d?lai, vous retrouverez votre historique complet.</p>
  </div>

  <p>Vous souhaitez vous r?abonner ?</p>
  <a href="https://applyflow.ch/pricing" style="display:inline-block; padding:12px 24px; background:#2563eb; color:white; border-radius:8px; text-decoration:none;">
