  </a>

  <p style="color:#6b7280; font-size:12px; margin-top:24px;">
    Des questions ? R?pondez ? cet email.<br>
    ApplyFlow - La recherche d'emploi automatis?e en Suisse romande
  </p>
</div>
`;

return [{
  json: {
    email,
    prenom,
    html,
    subject: 'Votre abonnement ApplyFlow a ?t? r?sili?'
  }
}];

// BUG-006: Stripe HMAC-SHA256 signature verification
// NOTE: require('crypto') is BLOCKED on n8n Cloud - using Web Crypto API instead
// Reference: https://docs.n8n.io/code/builtin/n8n-builtin-variables/
const sigHeader = $input.first().headers['stripe-signature'] || '';
const rawBody = $input.first().json.rawBody || JSON.stringify($input.first().json.body || $input.first().json);

// Parse stripe-signature header: t=timestamp,v1=hmac
const parts = {};
sigHeader.split(',').forEach(part => {
  const eq = part.indexOf('=');
  if (eq > 0) parts[part.substring(0, eq)] = part.substring(eq + 1);
});

const timestamp = parts['t'];
const v1 = parts['v1'];

if (!timestamp || !v1) {
  throw new Error('Stripe-Signature header missing or malformed');
}

const secret = $env['STRIPE_WEBHOOK_SECRET'] || '';
if (!secret) {
  // Soft fail during initial setup - MUST be set before go-live
  console.warn('[WF-STRIPE] STRIPE_WEBHOOK_SECRET not configured - skipping HMAC verification');
  return $input.all();
}

// Reconstruct the signed payload exactly as Stripe does
const signedPayload = `${timestamp}.${rawBody}`;

// HMAC-SHA256 via Web Crypto API (available in n8n Cloud sandbox)
const encoder = new TextEncoder();
const cryptoKey = await crypto.subtle.importKey(
  'raw', encoder.encode(secret),
  { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']
);
const sig = await crypto.subtle.sign('HMAC', cryptoKey, encoder.encode(signedPayload));
const expected = Array.from(new Uint8Array(sig)).map(b => b.toString(16).padStart(2, '0')).join('');

// Replay attack guard: reject events older than 5 minutes
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp, 10)) > 300) {
  throw new Error('Stripe webhook timestamp too old - possible replay attack');
}

if (expected !== v1) {
  throw new Error('Invalid Stripe signature - request rejected');
}

return $input.all();

